import React from "react";
import Svg from "./svg/Svg";
import styleButt from "./Button.module.scss";

const Button = (props) => {
  async function getListUsers() {
    const request = await fetch("http://localhost:5000/api/users", {
      method: "POST",
      headers: {
        Accept: "application/json",
        "Content-Type": "application/json",
        //@ts-ignore
        Authentication: JSON.parse(localStorage.getItem("user")).accessToken,
      },
      credentials: "include",
    });
    return request;
  }

  return (
    <button
      onClick={props.dispatch}
      className={styleButt.container__comment_but}
    >
      <Svg />
    </button>
  );
};

export default Button;
